// Normalize Gmail items into a clean array the LLM can chew.
const items = $input.all();
const cfg = $('Config').first().json;
const maxEmails = Number(cfg.max_emails_per_run) || 50;

const safe = (v, fallback = '') => (v === undefined || v === null) ? fallback : String(v).trim();

function parseFrom(rawFrom) {
  const s = safe(rawFrom);
  const match = s.match(/^\s*"?([^"<]*?)"?\s*<([^>]+)>\s*$/);
  if (match) return { name: match[1].trim() || match[2], email: match[2].trim() };
  return { name: s, email: s };
}

function pickSnippet(item) {
  if (item.snippet) return safe(item.snippet);
  if (item.text) return safe(item.text);
  if (item.html) return safe(item.html).replace(/<[^>]+>/g, ' ');
  return '';
}

const normalized = items.slice(0, maxEmails).map((it, i) => {
  const j = it.json || {};
  const headers = j.payload?.headers || [];
  const get = (n) => (headers.find(h => h.name?.toLowerCase() === n.toLowerCase())?.value) || '';
  const fromRaw = safe(j.from) || get('From');
  const subject = safe(j.subject) || get('Subject') || '(no subject)';
  const dateRaw = safe(j.date) || get('Date') || new Date().toISOString();
  const snippet = pickSnippet(j).slice(0, 300);
  const { name, email } = parseFrom(fromRaw);
  return {
    idx: i,
    id: safe(j.id, ''),
    threadId: safe(j.threadId, ''),
    from_email: email,
    from_name: name,
    subject,
    snippet,
    date: dateRaw
  };
});

return [{ json: { emails: normalized, total: normalized.length } }];

// Build batched prompt for Claude — one item per chunk of batch_size emails.
const cfg = $('Config').first().json;
const batchSize = Number(cfg.batch_size) || 25;
const { emails } = $input.item.json;

if (!emails || emails.length === 0) {
  return [{ json: { _skip: true, emails: [], total: 0 } }];
}

const system = `# IDENTITY
You are an email triage agent. You classify emails for a busy entrepreneur into one of four categories and assign each a priority.

# CATEGORIES
- "client"   : an existing paying customer or active project contact
- "prospect" : a new lead, sales enquiry, cold outreach, or warm intro
- "admin"    : invoices, banking, tax, government, infrastructure alerts, scheduling, calendar invites, anything operational
- "junk"     : newsletters, marketing, promo, social notifications, automated nags, anything ignorable

# PRIORITY
- 3 : reply today, time-sensitive or high-value
- 2 : reply this week
- 1 : low urgency, FYI, can wait or be archived

# OUTPUT FORMAT
Return STRICT JSON, no prose around it. An array, one object per input email, in the same order, schema:
[
  { "idx": <integer>, "category": "client|prospect|admin|junk", "priority": 1|2|3, "reason": "<8 words max>" }
]

# RULES
- Always return exactly one object per input email.
- Never invent fields. Never wrap in markdown fences.
- If unsure, default to "admin" with priority 1.`;

const batches = [];
for (let i = 0; i < emails.length; i += batchSize) {
  batches.push(emails.slice(i, i + batchSize));
}

return batches.map((batch) => {
  const userPrompt = `# EMAILS TO CLASSIFY\n${batch.map(e => `---\nidx: ${e.idx}\nfrom: ${e.from_name} <${e.from_email}>\nsubject: ${e.subject}\nsnippet: ${e.snippet}`).join('\n')}\n---\n\nReturn the JSON array now.`;
  return {
    json: {
      _claude_system: system,
      _claude_user: userPrompt,
      batch_emails: batch
    }
  };
});

// Parse Claude's reply, merge classifications back into the original email objects.
const response = $input.item.json;
const raw = (response?.content?.[0]?.text || '').trim();
const batchEmails = $input.item.json.batch_emails || $('Build Claude batch prompt').item.json.batch_emails || [];

function extractJsonArray(s) {
  if (!s) return null;
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/);
  const candidate = (fenced ? fenced[1] : s).trim();
  try { return JSON.parse(candidate); } catch (e) { /* fall through */ }
  const arrayMatch = candidate.match(/\[[\s\S]*\]/);
  if (arrayMatch) {
    try { return JSON.parse(arrayMatch[0]); } catch (e) { return null; }
  }
  return null;
}

const classified = extractJsonArray(raw) || [];
const byIdx = new Map(classified.map(c => [Number(c.idx), c]));

const merged = batchEmails.map((e) => {
  const c = byIdx.get(Number(e.idx)) || { category: 'admin', priority: 1, reason: 'parse_fallback' };
  return {
    ...e,
    category: ['client', 'prospect', 'admin', 'junk'].includes(c.category) ? c.category : 'admin',
    priority: [1, 2, 3].includes(Number(c.priority)) ? Number(c.priority) : 1,
    reason: String(c.reason || '').slice(0, 80)
  };
});

return merged.map(json => ({ json }));

// Aggregate, group by category, sort each group by priority + date desc.
const items = $input.all().map(i => i.json);

const groups = { client: [], prospect: [], admin: [], junk: [] };
for (const e of items) {
  if (groups[e.category]) groups[e.category].push(e);
}

for (const cat of Object.keys(groups)) {
  groups[cat].sort((a, b) => {
    if (b.priority !== a.priority) return b.priority - a.priority;
    return new Date(b.date).getTime() - new Date(a.date).getTime();
  });
}

const total = items.length;
const counts = {
  client: groups.client.length,
  prospect: groups.prospect.length,
  admin: groups.admin.length,
  junk: groups.junk.length
};

return [{ json: { groups, counts, total } }];

// Build the final HTML digest email — brand-aligned Taiyka.
const { groups, counts, total } = $input.item.json;

const today = new Date().toLocaleDateString('fr-FR', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const CATEGORY_META = {
  client:   { label: 'Clients',   icon: '🔴', color: '#ff6b6b' },
  prospect: { label: 'Prospects', icon: '🟡', color: '#ffd43b' },
  admin:    { label: 'Admin',     icon: '📋', color: '#00A6FF' },
  junk:     { label: 'Junk',      icon: '🗑️', color: '#868e96' }
};

function escapeHtml(s) {
  return String(s || '').replace(/[&<>"']/g, m => ({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;'
  }[m]));
}

function renderSection(catKey) {
  const meta = CATEGORY_META[catKey];
  const list = (groups[catKey] || []).slice(0, 5);
  const count = counts[catKey] || 0;

  const rows = list.map(e => {
    const subj = escapeHtml(e.subject);
    const from = escapeHtml(e.from_name || e.from_email);
    const reason = escapeHtml(e.reason);
    const mailto = `mailto:${encodeURIComponent(e.from_email)}?subject=${encodeURIComponent('Re: ' + e.subject)}`;
    const dot = '•'.repeat(e.priority);
    return `<tr><td style="padding:8px 6px;border-bottom:1px solid #1a2a4a;color:${meta.color};font-weight:700;font-size:12px;vertical-align:top;">${dot}</td><td style="padding:8px 6px;border-bottom:1px solid #1a2a4a;vertical-align:top;"><a href="${mailto}" style="color:#00E5FF;text-decoration:none;font-weight:600;">${subj}</a><div style="color:#9aa4b2;font-size:12px;margin-top:2px;">${from} · ${reason}</div></td></tr>`;
  }).join('');

  return `<div style="margin:24px 0;"><h2 style="color:#FFFFFF;font-size:18px;margin:0 0 8px 0;">${meta.icon} ${meta.label} <span style="color:${meta.color};font-weight:400;font-size:14px;margin-left:6px;">(${count})</span></h2>${count === 0 ? `<p style="color:#9aa4b2;font-size:14px;margin:4px 0;">Aucun email dans cette catégorie.</p>` : `<table style="width:100%;border-collapse:collapse;background:#0A1628;border-radius:8px;">${rows}</table>`}</div>`;
}

const html = `<div style="font-family:Inter,Arial,sans-serif;max-width:680px;margin:0 auto;background:#0A1628;color:#FFFFFF;padding:32px;border-radius:16px;"><div style="border-bottom:2px solid #00A6FF;padding-bottom:16px;margin-bottom:16px;"><h1 style="color:#FFFFFF;font-size:22px;margin:0;">Triage du ${escapeHtml(today)}</h1><p style="color:#9aa4b2;font-size:14px;margin:6px 0 0 0;">${total} email${total > 1 ? 's' : ''} sur les 24 dernières heures · ${counts.client} clients · ${counts.prospect} prospects · ${counts.admin} admin · ${counts.junk} junk</p></div>${['client', 'prospect', 'admin', 'junk'].map(renderSection).join('')}<div style="margin-top:32px;padding-top:16px;border-top:1px solid #1a2a4a;color:#6c757d;font-size:12px;text-align:center;">Powered by Taiyka · Skool community welcome gift</div></div>`;

return [{ json: { html, total, counts } }];
